#include <bits/stdc++.h>using namespace std;int n,t,a[55],x;bool b[55];void dfs(int m){    if(m>n){        if((x++)<n){            for(int i=1;i<=n;i++){                cout<<a[i]<<" ";            }            cout<<endl;        }        return;    }    for(int i=1;i<=n;i++){        if(b[i]){            continue;        }        if(m>2){            if(a[m-1]+a[m-2]==i){                continue;            }        }        b[i]=1;        a[m]=i;        dfs(m+1);        a[m]=0;        b[i]=0;        if(x>n){            return;        }    }}int main (){    cin>>t;    while(t--){        x=0;        cin>>n;        dfs(1);    }    return 0;}